import gc
import weakref
import tracemalloc
from functools import lru_cache

# Leak 1: Unbounded cache
class LeakyCache:
    def __init__(self):
        self._cache = {}  # grows forever!

    def get(self, key):
        if key not in self._cache:
            self._cache[key] = self._expensive_compute(key)
        return self._cache[key]

    def _expensive_compute(self, key):
        return [0] * 10000  # big object

# Fix: use LRU cache or WeakValueDictionary
class FixedCache:
    def __init__(self, maxsize=100):
        self._cache = {}
        self._maxsize = maxsize

    def get(self, key):
        if key not in self._cache:
            if len(self._cache) >= self._maxsize:
                oldest = next(iter(self._cache))
                del self._cache[oldest]
            self._cache[key] = self._expensive_compute(key)
        return self._cache[key]

    def _expensive_compute(self, key):
        return [0] * 10000

# Leak 2: Mutable default argument
def leaky_function(items=[]):
    items.append("data")
    return items

leaky_function()  # ['data']
leaky_function()  # ['data', 'data'] -- accumulating!
leaky_function()  # ['data', 'data', 'data']

# Fix:
def fixed_function(items=None):
    if items is None:
        items = []
    items.append("data")
    return items

# Leak 3: Closure capturing large scope
def create_processor():
    large_data = [0] * 1_000_000  # captured by closure!

    def process(x):
        return x * 2  # doesn't even use large_data

    return process  # large_data stays alive

# Fix: only capture what you need
def create_processor_fixed():
    large_data = [0] * 1_000_000
    result = sum(large_data)  # extract what you need
    del large_data  # explicitly free

    def process(x):
        return x * result

    return process

