# Detecting leaks with tracemalloc
def find_leaks():
    tracemalloc.start()
    snapshot1 = tracemalloc.take_snapshot()

    # Run suspected leaky code
    cache = LeakyCache()
    for i in range(1000):
        cache.get(f"key_{i}")

    snapshot2 = tracemalloc.take_snapshot()
    diff = snapshot2.compare_to(snapshot1, 'lineno')

    print("Memory growth:")
    for stat in diff[:5]:
        print(f"  {stat}")

    tracemalloc.stop()

find_leaks()

